INSERT INTO t_repair_acceptance (
    work_order_id, project_id, settlement_id, tenant_id, policy_id,
    round_no, status, submitted_by_user_id
) VALUES (
    NULL, #{row.projectId}, #{row.settlementId}, #{row.tenantId}, #{row.policyId},
    (SELECT COALESCE(MAX(round_no), 0) + 1 FROM t_repair_acceptance WHERE project_id = #{row.projectId}),
    'COLLECTING', #{submittedByUserId}
)

mapper.select:
